import{_ as l,C as d,o,c as r,a3 as c,b as i,w as a,a as n,E as s,a4 as p}from"./chunks/framework.aYYe0dfI.js";const P=JSON.parse('{"title":"Module client","description":"client 模块是 LLM（大语言模型）网络通信的异步客户端层。它提供了三项公开的模板函数——call_completion_async、call_llm_async 和 call_structured_async，分别用于发起补全、通用 LLM 调用和结构化输出请求。这些函数通过模板参数 Protocol 抽象不同 LLM 提供者的协议细节，并利用 kota::event_loop 进行异步回调调度；内部依赖 clore::net::detail::select_event_loop 将可选的循环指针解析为确定引用，从而简化调用者的事件循环管理。","frontmatter":{"title":"Module client","description":"client 模块是 LLM（大语言模型）网络通信的异步客户端层。它提供了三项公开的模板函数——call_completion_async、call_llm_async 和 call_structured_async，分别用于发起补全、通用 LLM 调用和结构化输出请求。这些函数通过模板参数 Protocol 抽象不同 LLM 提供者的协议细节，并利用 kota::event_loop 进行异步回调调度；内部依赖 clore::net::detail::select_event_loop 将可选的循环指针解析为确定引用，从而简化调用者的事件循环管理。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/client/index.md","filePath":"zh/clore/modules/client/index.md"}'),u={name:"zh/clore/modules/client/index.md"};function h(m,e,_,f,b,q){const t=d("Mermaid");return o(),r("div",null,[e[1]||(e[1]=c('<h1 id="module-client" tabindex="-1">Module <code>client</code> <a class="header-anchor" href="#module-client" aria-label="Permalink to &quot;Module `client`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>client</code> 模块是 LLM（大语言模型）网络通信的异步客户端层。它提供了三项公开的模板函数——<code>call_completion_async</code>、<code>call_llm_async</code> 和 <code>call_structured_async</code>，分别用于发起补全、通用 LLM 调用和结构化输出请求。这些函数通过模板参数 <code>Protocol</code> 抽象不同 LLM 提供者的协议细节，并利用 <code>kota::event_loop</code> 进行异步回调调度；内部依赖 <code>clore::net::detail::select_event_loop</code> 将可选的循环指针解析为确定引用，从而简化调用者的事件循环管理。</p><p>该模块的公共实现范围涵盖这些异步入口点及其共用的辅助设施，不对外暴露底层 HTTP 请求细节、协议解析或 schema 处理逻辑。它依赖 <code>http</code>、<code>protocol</code>、<code>schema</code> 与 <code>support</code> 模块，共同构成针对 LLM 的通用、可扩展的异步通信能力。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../http/"><code>http</code></a></li><li><a href="./../protocol/"><code>protocol</code></a></li><li><a href="./../schema/"><code>schema</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../anthropic/"><code>anthropic</code></a></li><li><a href="./../openai/"><code>openai</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',9)),(o(),i(p,null,{default:a(()=>[s(t,{id:"mermaid-60",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22client%22%5D%0A%20%20%20%20I0%5B%22http%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22protocol%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22schema%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A%20%20%20%20I3%5B%22support%22%5D%0A%20%20%20%20I3%20--%3E%20M0%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=c('<h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-call-completion-async" tabindex="-1"><code>clore::net::call_completion_async</code> <a class="header-anchor" href="#clore-net-call-completion-async" aria-label="Permalink to &quot;`clore::net::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:16</code></p><p>Definition: <code>network/client.cppm:57</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>实现摘要如下：</p><p><code>clore::net::call_completion_async</code> 是一个模板化的异步函数，负责向大模型服务发送补全请求并处理响应。其核心算法是一个最多四次迭代的重试循环，内部通过 <code>Protocol</code> 模板参数静态派生子类协议。每次迭代首先从 <code>get_probed_capabilities</code> 获取当前协议的能力缓存，再调用 <code>sanitize_request_for_capabilities</code> 剔除请求中不受支持的功能。随后构造请求 JSON、解析环境变量，并通过 <code>detail::select_event_loop</code> 确定活跃事件循环，最后执行 <code>detail::perform_http_request_async</code> 发送 HTTP 请求并接收原始响应。</p><p>当收到 HTTP 4xx 状态码时，函数会利用 <code>is_feature_rejection_error</code> 和 <code>parse_rejected_feature_from_error</code> 判断是否为特性拒绝错误（如 <code>response_format</code>、<code>tool_choice</code>、<code>parallel_tool_calls</code>、<code>tools</code>）。若是此类错误且重试次数未超过上限，则原子地更新缓存中对应能力位（如 <code>caps.supports_tools</code>），使用清理后的请求重新进入循环；若能力降级后仍无法满足原始需求（如工具被剥离），则立即返回 <code>LLMError</code>。循环正常退出后解析成功的响应，否则在耗尽重试次数后返回能力探测耗尽错误。整个控制流依赖 <code>clore::net::detail::select_event_loop</code> 进行事件循环适配，并使用 <code>kota::task</code> 和 <code>kota::fail</code> 实现协程化错误传递。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies atomic capability flags in the <code>ProbedCapabilities</code> instance returned by <code>get_probed_capabilities</code></li><li>Performs an asynchronous HTTP request to the LLM provider</li><li>Logs warnings via <code>logging::warn</code> when a feature is rejected and retrying</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>Parameter <code>request</code> (a <code>CompletionRequest</code>)</li><li>Global <code>ProbedCapabilities</code> cache accessed via <code>get_probed_capabilities</code></li><li>Environment variables read by <code>Protocol::read_environment</code></li><li><code>Protocol</code> static members such as <code>provider_name</code></li><li><code>loop</code> parameter to select the event loop</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Atomic boolean members of the <code>ProbedCapabilities</code> object (e.g., <code>supports_json_schema</code>, <code>supports_tools</code>)</li><li>Log output via <code>logging::warn</code></li><li>Coroutine promise state (via <code>co_await</code> and <code>co_return</code>)</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called as a coroutine with <code>co_await</code></li><li>Used to perform completion requests with automatic capability probing</li><li>Integrates with <code>clore::net::detail::perform_http_request_async</code> for HTTP transport</li></ul><h3 id="clore-net-call-llm-async" tabindex="-1"><code>clore::net::call_llm_async</code> <a class="header-anchor" href="#clore-net-call-llm-async" aria-label="Permalink to &quot;`clore::net::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:20</code></p><p>Definition: <code>network/client.cppm:137</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>该函数是一个协程模板，内部首先通过 <code>detail::select_event_loop</code> 将传入的 <code>loop</code> 指针解析为活跃的事件循环引用 <code>active_loop</code>。随后构造一个由 <code>clore::net::detail::request_text_once_async</code> 驱动的异步请求管道：它接受一个 lambda，该 lambda 将 <code>clore::net::CompletionRequest</code> 和事件循环引用转发给 <code>call_completion_async</code>；同时接收 <code>model</code>、<code>system_prompt</code> 和 <code>request</code> 作为外部参数，并以 <code>active_loop</code> 作为执行环境。整个协程的返回值经由 <code>detail::unwrap_caught_result</code> 展开，并在取消时通过 <code>.catch_cancel()</code> 捕获，以 <code>&quot;LLM request cancelled&quot;</code> 字符串格式化错误信息。核心控制流遵循“选择循环 → 构造请求 → 发送 → 展开并处理取消”的顺序，依赖 <code>detail::select_event_loop</code> 提供事件循环决策，依赖 <code>request_text_once_async</code> 和 <code>call_completion_async</code> 完成实际的网络交互与协议编解码。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Calls <code>call_completion_async</code> which performs network I/O for the LLM request</li><li>May cancel the coroutine, triggering cancellation-related side effects</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>model</code> (<code>std::string_view</code>)</li><li><code>system_prompt</code> (<code>std::string_view</code>)</li><li><code>request</code> (<code>clore::net::PromptRequest</code>)</li><li><code>loop</code> (<code>kota::event_loop</code>*)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Return value (<code>kota::task&lt;std::string, clore::net::LLMError&gt;</code>) containing the LLM response or error</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by callers requiring asynchronous text completion from an LLM</li><li>Often invoked with a custom event loop for non-blocking I/O</li></ul><h3 id="clore-net-call-llm-async-1" tabindex="-1"><code>clore::net::call_llm_async</code> <a class="header-anchor" href="#clore-net-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:27</code></p><p>Definition: <code>network/client.cppm:156</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>函数 <code>clore::net::call_llm_async</code> 的实现是一个协程，它首先通过 <code>detail::select_event_loop</code> 获取活动的事件循环引用，然后委托给 <code>clore::net::detail::request_text_once_async</code>。该函数接收一个 lambda 闭包，在闭包内构造 <code>CompletionRequest</code> 并调用 <code>call_completion_async&lt;Protocol&gt;</code> 发起实际的异步请求；同时还传递了模型标识、系统提示和一个 <code>PromptRequest</code> 实例（其 <code>prompt</code> 字段来自调用参数，<code>response_format</code> 为 <code>std::nullopt</code>，<code>output_contract</code> 设为 <code>PromptOutputContract::Markdown</code>）。最终结果通过 <code>.or_fail()</code> 将错误转换为 <code>clore::net::LLMError</code> 并返回。整个流程的协程依赖 <code>detail::select_event_loop</code> 和 <code>detail::request_text_once_async</code>，后者内部封装了重试与错误处理逻辑。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>发起网络 I/O 请求以调用语言模型</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>参数 <code>model</code></li><li>参数 <code>system_prompt</code></li><li>参数 <code>prompt</code></li><li>参数 <code>loop</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>用于异步获取 LLM 生成的文本回复</li><li>与其他 <code>call_llm_async</code> 重载类似，但支持自定义事件循环</li></ul><h3 id="clore-net-call-structured-async" tabindex="-1"><code>clore::net::call_structured_async</code> <a class="header-anchor" href="#clore-net-call-structured-async" aria-label="Permalink to &quot;`clore::net::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:34</code></p><p>Definition: <code>network/client.cppm:177</code></p><p>Declaration: <a href="./../../namespaces/clore/net/"><code>Namespace clore::net</code></a></p><p>函数 <code>clore::net::call_structured_async</code> 首先通过 <code>clore::net::schema::response_format&lt;T&gt;()</code> 获取类型 <code>T</code> 对应的结构化响应格式，若该操作失败则立即通过 <code>kota::fail</code> 返回错误。随后构造一个 <code>clore::net::CompletionRequest</code> 实例，将 <code>model</code>、<code>system_prompt</code>、<code>prompt</code> 以及获取到的 <code>response_format</code> 填入其中，并将 <code>tools</code>、<code>tool_choice</code>、<code>parallel_tool_calls</code> 置为空值。接着调用 <code>clore::net::call_completion_async&lt;Protocol&gt;</code> 发送该请求，通过 <code>.or_fail()</code> 等待异步结果并自动处理异常。</p><p>得到原始响应后，函数使用 <code>clore::net::protocol::parse_response_text&lt;T&gt;</code> 将响应文本解析为目标类型 <code>T</code>。若解析失败同样通过 <code>kota::fail</code> 返回错误，成功则协程返回解析后的值。整个流程严格依赖 <code>Protocol</code> 参数指定的协议实现以及 <code>kota</code> 提供的异步原语，核心算法围绕“获取格式 → 构造请求 → 调用完成API → 解析结构化结果”这一线性步骤展开。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Initiates an asynchronous network I/O operation via <code>call_completion_async</code>.</li></ul><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>model</code></li><li><code>system_prompt</code></li><li><code>prompt</code></li><li><code>loop</code></li><li>Global schema configuration via <code>clore::net::schema::response_format&lt;T&gt;()</code></li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>The returned <code>kota::task</code> object that will eventually resolve to a value of type <code>T</code> or an error.</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to make structured asynchronous LLM calls where the response is parsed into a specific C++ type.</li><li>Typically invoked with a concrete <code>Protocol</code> and <code>T</code> type arguments.</li><li>Often called within other coroutines or event loop contexts.</li></ul><h3 id="clore-net-detail-select-event-loop" tabindex="-1"><code>clore::net::detail::select_event_loop</code> <a class="header-anchor" href="#clore-net-detail-select-event-loop" aria-label="Permalink to &quot;`clore::net::detail::select_event_loop`&quot;">​</a></h3><p>Declaration: <code>network/client.cppm:45</code></p><p>Definition: <code>network/client.cppm:45</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>Implementation: <a href="./functions/select-event-loop">Implementation</a></p><p>该函数首先检查传入的 <code>loop</code> 指针是否为空；若非空则直接返回其引用，否则回退到通过 <code>kota::event_loop::current()</code> 获取当前线程的默认事件循环。这一选择逻辑依赖于调用方保证当 <code>loop</code> 为空时当前线程已关联一个有效的 <code>kota::event_loop</code> 实例，否则行为未定义。内部没有循环或异步操作，仅是一个简单的条件转发，将外部提供的循环或线程局部默认循环统一为引用返回。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>loop</code> parameter</li><li><code>kota::event_loop::current()</code> result</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by <code>call_completion_async</code> and <code>call_llm_async</code> to obtain a valid event loop reference from an optional pointer</li><li>Invoked with a potentially null <code>kota::event_loop*</code> to default to the current loop</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>client 模块是网络层中面向 LLM 客户端操作的核心入口，它通过一组模板异步函数（如 <code>call_completion_async</code>、<code>call_llm_async</code>、<code>call_structured_async</code>）对外暴露统一的异步调用接口。这些函数均接受一个可选的 <code>kota::event_loop*</code> 参数，允许调用者将异步回调绑定到指定的事件循环上；若为空则使用 <code>detail::select_event_loop</code> 选择的默认循环。模块内部解耦为公共调用桩与底层实现：<code>detail</code> 子命名空间封装了事件循环选择等辅助逻辑，而协议处理、HTTP 通信、JSON 模式生成等功能则分别委托给所依赖的 <code>protocol</code>、<code>http</code>、<code>schema</code> 模块，基础文本与文件操作依赖 <code>support</code> 模块。</p><p>实现结构上，client 模块以强类型接口隔离了调用者与异步细节。每个公开函数都是轻量模板，负责解析参数、通过 <code>detail</code> 获取可靠的事件循环引用，再将请求参数组合并转发给下层协议与 HTTP 模块。关键的异步状态（如 <code>loop</code>、<code>request</code>、<code>system_prompt</code>、<code>model</code>）在模块内部以局部变量或公开成员（如 <code>parsed</code>、<code>request_json</code>、<code>raw_response</code>）的形式存在，支撑着回调上下文的管理。这种分层设计使得客户端代码只需关心模型、提示和事件循环，而将协议适配、请求编排和响应解析隐藏在下层。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../http/">Module http</a></li><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../schema/">Module schema</a></li><li><a href="./../support/">Module support</a></li></ul>',71))])}const k=l(u,[["render",h]]);export{P as __pageData,k as default};
